Method.Source:
/// <summary>
/// This method contains logic for disable/enable the ConversionToInventoryButton
/// when CylinderTracking feature is enabled/disabled
/// </summary>
/// <returns>int</returns>
int active()
{
    int ret =  next active();
    this.updateDesignETG();
    return ret;
}

/// <summary>
/// This method contains logic for disable/enable the ConversionToInventoryButton
/// </summary>
public void updateDesignETG()
{
    this.formRun().design().controlName(formControlStr(AssetTable, ETGConversionToInventory)).visible(SalesParameters::find().ETGEnableCylinderTracking);
}
